package com.pqc.core.service;
import com.pqc.core.dto.*; import com.pqc.core.entity.*; import com.pqc.core.repository.*; import org.junit.jupiter.api.Test; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension; import org.springframework.web.server.ResponseStatusException; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.Optional; import static org.assertj.core.api.Assertions.*; import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class MarketingAdminServiceTest {@Mock OfferRepository offers;@Mock MarketingCampaignRepository campaigns;@Mock MarketingBannerRepository banners;@Mock MarketingNotificationRepository notifications;@Mock UserRepository users;@InjectMocks MarketingAdminService service;
private OfferCreateRequest request(){return new OfferCreateRequest("FIRST50","First",null,DiscountType.PERCENTAGE,BigDecimal.TEN,BigDecimal.ZERO,BigDecimal.TEN,100,Role.CUSTOMER,LocalDateTime.now(),LocalDateTime.now().plusDays(1));}
@Test void rejectsDuplicateCode(){when(offers.existsByCodeIgnoreCase("FIRST50")).thenReturn(true);assertThatThrownBy(()->service.createOffer(request())).isInstanceOf(ResponseStatusException.class).hasMessageContaining("409");}
@Test void rejectsInvalidDates(){OfferCreateRequest r=request();assertThatThrownBy(()->service.createOffer(new OfferCreateRequest(r.code(),r.title(),null,r.discountType(),r.discountValue(),r.minOrderAmount(),null,null,null,r.endsAt(),r.startsAt()))).isInstanceOf(ResponseStatusException.class).hasMessageContaining("400");}
@Test void rejectsInvalidCampaignTransition(){MarketingCampaign c=MarketingCampaign.builder().id(1L).status(CampaignStatus.COMPLETED).build();when(campaigns.findById(1L)).thenReturn(Optional.of(c));assertThatThrownBy(()->service.updateCampaignStatus(1L,new CampaignStatusUpdateRequest(CampaignStatus.ACTIVE))).isInstanceOf(ResponseStatusException.class).hasMessageContaining("409");}}
